# R-side timing script for JAX RS benchmark.
# Called by jax_rs_benchmark.py with arguments:
#   Rscript r_timing_template.R <family> <data_csv> <n_reps> <out_csv>
#
# Reads data from a CSV file generated by Python (same data as Python benchmark).
# Runs gamlss() n_reps times inside R, measures wall time with proc.time().
# Writes timing results to out_csv.
# This eliminates Rscript startup overhead from per-call timing.

suppressPackageStartupMessages({
  library(gamlss)
  library(gamlss.dist)
})

args        <- commandArgs(trailingOnly = TRUE)
family_name <- args[1]
data_csv    <- args[2]
n_reps      <- as.integer(args[3])
out_csv     <- args[4]

# Read data generated by Python
df <- read.csv(data_csv)
y  <- df$y
x  <- df$x

# Select family object
fam_obj <- switch(family_name,
  "NO"  = NO(),
  "GA"  = GA(),
  "PO"  = PO(),
  "BI"  = BI(),
  "WEI" = WEI(),
  "TF"  = TF(),
  stop(paste("Unknown family:", family_name))
)

# Warm-up run (not timed) — triggers R's internal JIT-equivalent
invisible(suppressMessages(
  gamlss(y ~ x, family = fam_obj, data = df,
         control = gamlss.control(trace = FALSE))
))

# Timed runs
times_ms  <- numeric(n_reps)
deviances <- numeric(n_reps)

for (i in seq_len(n_reps)) {
  t0 <- proc.time()["elapsed"]
  fit <- suppressMessages(
    gamlss(y ~ x, family = fam_obj, data = df,
           control = gamlss.control(trace = FALSE))
  )
  t1 <- proc.time()["elapsed"]
  times_ms[i]  <- (t1 - t0) * 1000.0
  deviances[i] <- fit$G.deviance
}

result <- data.frame(
  family   = family_name,
  n        = nrow(df),
  rep      = seq_len(n_reps),
  time_ms  = times_ms,
  deviance = deviances
)

write.csv(result, out_csv, row.names = FALSE)
cat(sprintf(
  "R timing done: family=%s n=%d reps=%d median_ms=%.1f deviance=%.6f\n",
  family_name, nrow(df), n_reps,
  median(times_ms), median(deviances)
))
